[TestMethod]
public void Circle_Draw_DelegatesToRenderer() {
  var circle = new Circle(new VectorRenderer(), 3f);
  circle.Draw();
  Assert.IsTrue(true);
}

[TestMethod]
public void Bridge_AllowsSwappingImplementation() {
  Shape shape = new Circle(new RasterRenderer(), 2f);
  shape.Draw();
  Assert.IsNotNull(shape);
}
